import { AudioSourceInfo, FfiHandle } from '@livekit/rtc-ffi-bindings';
import { AudioFrame } from './audio_frame.js';

declare class AudioSource {
    /** @internal */
    info: AudioSourceInfo;
    /** @internal */
    ffiHandle: FfiHandle;
    /** @internal */
    lastCapture: number;
    /** @internal */
    currentQueueSize: number;
    /** @internal */
    release: () => void;
    promise: Promise<void>;
    /** @internal */
    timeout?: ReturnType<typeof setTimeout>;
    /** @internal */
    closed: boolean;
    sampleRate: number;
    numChannels: number;
    queueSize: number;
    constructor(sampleRate: number, numChannels: number, queueSize?: number);
    get queuedDuration(): number;
    clearQueue(): void;
    /** @internal */
    newPromise(): Promise<void>;
    waitForPlayout(): Promise<void>;
    captureFrame(frame: AudioFrame): Promise<void>;
    close(): Promise<void>;
}

export { AudioSource };
